```class Solution {
public:
    int maximumLength(string s) {
        int n = s.size();
        int res = -1;
        for (int len = 1; len <= n; len++) {
            unordered_map<string, int> mp;
            for (int i = 0; i <= n - len; i++) {
                string substr = s.substr(i, len);
                if (substr[0] == substr.back() && count(substr.begin(), substr.end(), substr[0]) == len) {
                    mp[substr]++;
                    if (mp[substr] >= 3) {
                        res = max(res, len);
                    }
                }
            }
        }
        return res;
    }
};
